features.snippet:
logic clk, a, b;
sequence seq_clocked_delay;
  @(posedge clk) a ##2 b;
endsequence
property p;
  @(posedge clk) a |-> ##2 b;
endproperty
assert property (p);

logic clk, req, ack;
property p_delay_range;
  @(negedge clk) req |-> ##[1:4] ack;
endproperty
assert property (p_delay_range);

logic clk, a, b, c;
property p_merge;
  @(posedge clk) a ##1 b ##1 c;
endproperty
assert property (p_merge);
